solution:
  @startuml

class Customer {
    String Name
    String email
}
class InsurancePolicy {
    String Type
    Double MonthlyPrice
    Double YearlyPrice
}
class Contract {
    String Status
    String InvoiceFrequency
}
class Invoice {}

class Broker{
    String Name
}
class Claim {
    Double CompensationTotal
    Double calculateCompenstationSum()
}
class ClaimCase {
    String Status
    String CompensationDecision
}
class Report {}
class Estimator {
    String AreaOfExpertise
}
class CompensationPayment {
    Date PaymentDate
}

Customer "1"--"0..*" Contract
Contract "1" -- "0..*" Invoice
InsurancePolicy "1" -- "0..*" Contract
Contract "1" -- "0..*" ClaimCase
Customer "1" -- "0..*" Claim
Claim "1" -- "0..*" ClaimCase
ClaimCase "1" -- "0..*" CompensationPayment
Estimator "0..*" - "0..*" ClaimCase
(ClaimCase,Estimator) .. Report
Customer "0..*" - "0..1" Broker


@enduml

  @startuml
    class Bank

    class Branch

    class Customer {
        String firstName
        String lastName
    }

    class Account {
        int accountNumber
        double balance
    }

    class SavingsAccount

    class CheckingAccount {
        double overdraftLimit
    }

    Bank "1" o-- "*" Branch
    Bank "*" -- "*" Customer
    Customer "1" --> "1..5" Account
    Account <|-- SavingsAccount
    Account <|-- CheckingAccount
@enduml

 @startuml
    class User {
        String username
        String password
        String email
    }

    class Administrator {
        String idCardNumber
    }

    class WebPortal {
        String versionNumber
        String url
    }

    class Building {
        String id
        String label
        String address
        int yearOfConstruction
    }

    class Entry {
        String name
        boolean public
    }

    class TextEntry {
        String text
    }

    class NumericEntry {
        double value
        String unit
    }

    class EntryGroup

    enum EnergyClass <<enum>> {
        A
        B
        C
        D
    }

    class Comment {
        String text
    }

    class Image {
        String fileName
    }

    WebPortal "1" --> "*" Entry : id
    WebPortal "0..1" --> "1" User : username
    EntryGroup "1" *-- "*" Entry

    Entry <|-- TextEntry
    Entry <|-- NumericEntry

    User <|-- Administrator

    User "1" --> "*" Building : owner
    User "1" --> "*" Building : author
    Building "1" --> "*" Comment
    Building "1" --> "1" Image : profilePicture
    Building "1" --> "1" EnergyClass
@enduml

 @startuml

enum Shift <<enum>> {
    Morning
    Afternoon
    Night
}


class BusVehicle {
    String LicencePlate
    Boolean InRepairShop
}

class Route {
    Int Number
}

class RouteAssignment {
    Date Date
}

class Driver {
    String Name
    String Id
    Boolean OnSickLeave
}

class DriverSchedule{
    Shift Shift
}

BusVehicle "1" -- "0..*" RouteAssignment
Route "1" -- "0..*" RouteAssignment

Driver "1" -- "0..*" DriverSchedule
RouteAssignment "1" -- "0..*" DriverSchedule

@enduml

 @startuml

class Order {
    Int OrderNumber
    Int OrderQuantity
    Date OrderDate
    Date DeliveryDate
}

class Category {
    String Name
}

class Product {
    String Name
    String Description
    Double NetPrice
}

class Representative {
    String FirstName
    String LastName
    Int Ssn
    String PhoneNumber
    String Email
}

class Manufacturer {
    String Name
}

class Country {
    String Name
    Double VAT
    String Currency
    Float ConversionRate
}

class Customer {
    String Name
    String Address
    String PhoneNumber
    String Email
}


Product "1"--"*" Order : contains
Category "1"--"*" Product: belongsTo
Representative "1"--"*" Order : placedBy
Manufacturer "*"--"*" Country
Product . (Manufacturer,Country)
Product "*"--"*" Country : soldIn
Representative "*"-"1" Country : responsibleFor
Order "*"-"1" Customer : orders
Country "*"--"*" Customer : resell


@enduml

 @startuml

    class SensorController {
        id
    }

    class Sensor {
        Integer id
        String description
        Double threshold
    }

    class Measurement {
        Double value
        Long timestamp
    }

    class TemperatureSensor {
        Double min
        Double max
    }

    class PowerMeter {
        Double totalConsumption
    }

    enum Unit <<enum>> {
        CELSIUS
        WATT
    }

    class Room {
        String label
    }

    class Apartment {
        String address
        String email
    }

    class Resident {
        String username
        String password
        Boolean isAdmin
    }

    SensorController "1" --> "0..1" Sensor
    Sensor "1" --> "*" Measurement
    Sensor "1" --> "1" Measurement : lastValue
    Sensor <|-- TemperatureSensor
    Sensor <|-- PowerMeter
    Sensor "1" --> "1" Unit
    SensorController "1" --> "1" Room
    Room "2..*" *-- "1" Apartment
    Apartment "1" --> "*" Resident
    Apartment "1" --> "*" Sensor

@enduml

 @startuml

class Person {
    Int PersonID
    String PhoneNumber
    String Keywords
}

class ResearchInstitution {
    Int InstitutionCode
}

class Article {
    Int DOI
    String Title
}

class Author {
    Int Position
}

class PeerReviewedPaper {
    Int CitationCount
}

class TechnicalReport {

}

class Publisher {
    String Name
}

class Journal {
    String Name
    Double ImpactFactor
}


TechnicalReport --|> Article : {total; disjoint}
Article <|-- PeerReviewedPaper
Article "*"-"*" Person
Author .. (Article,Person)
ResearchInstitution "1"--"*" Person : worksFor
Person "*"--"*" PeerReviewedPaper : reviews
ResearchInstitution "*"--"*" Journal : subscribesTo
Publisher "1"--"*" Journal : publishes
Journal "1"--"*" PeerReviewedPaper
ResearchInstitution "1"--"*" TechnicalReport : publishes

@enduml

 @startuml

class User {
    Int UserID
    String Name
    String Email
    Date BirthDate
}

abstract class Account {
    Int AccountNumber
}

class BusinessAccount {
    String CompanyName
}

class PersonalAccount {}

class FriendRequest {}

abstract class Page {
    String PageName
    Int Visits
}

class PersonalPage {}

class Privilege {
    String TypeOfPrivilege
}

class AdvertisementPage {
    Double BounceRate
    Double ClickThroughRate
    Double CoversionRate
}

User "1"--"1" Account
Account <|-- BusinessAccount
Account <|-- PersonalAccount
BusinessAccount "1"--"*" AdvertisementPage
PersonalAccount "1"--"*" PersonalPage : administrator
PersonalAccount "*"--"*" PersonalPage
Privilege .. (PersonalAccount,PersonalPage)
FriendRequest "*"-"1" PersonalAccount : sender
FriendRequest "*"-"1" PersonalAccount : receiver
AdvertisementPage --|> Page
PersonalPage --|> Page


@enduml

 @startuml

class Center {
    String name
    String Address
}

class Room {
    Int RoomNr
    Int MaxCapacity
}

class Session {
    DateTime StartDateTime

}

class IndividualSession {}

class GroupSession {
    String Type
}

class Person {
    String FirstName
    String Lastname
    Date BirthDate
}

class Member {}

class Trainer {
    String Diploma
}

Center "1"--"1..*" Room
Room "1"-"*" Session
Session <|-- GroupSession : {total; disjoint}
Session <|- IndividualSession
IndividualSession "*"-"1" Member
Member "*"--"*" GroupSession
Person <|-- Member : {partial; overlap}
Person <|-- Trainer
Trainer "1"--"*" GroupSession

@enduml

 @startuml

enum Interval <<enum>> {
    Weekly
    Monthly
    EveryHalfYear
    Yearly
}

enum AccessType <<enum>> {
    Reservable
    WalkIn
    DropOff
}

enum DayOfWeek <<enum>> {
    Monday
    Tuesday
    Wednesday
    Thursday
    Friday
    Saturday
    Sunday
}


class Person {
    String LastName
    String FirstName
    String Address
    String PhoneNumber
}

abstract class PersonRole {
    Int IdNumber
}

class Patient {
    String DateOfBirth
}

class Doctor {
    String Signature
}

class Requisition {
    String EffectiveDate
    Int RepetitionCount
    Interval RepetitionInterval
}

class TestResult {
    Boolean Result
    String Report
}

class SpecificTest {
    Date Date
}

class Appointment {
    String Confirmation
    Date Date
    String startTime
    String endTime
}

class BusinessHour {
    DayOfWeek DayOfWeek
    String startTime
    String endTime
}

class Lab {
    String RegistrationNumber
    String Name
    String Address
    Boolean ChangeCancelFee
}

class Test {
    String Name
    String Duration
}

class TestType {
    String Name
    String DurationAdditive
    AccessType Access
}



PersonRole <|-- Patient
PersonRole <|-- Doctor

Person "1" -- "0..2" PersonRole
Patient "1" -- "*" Requisition
Lab "1" - "*" Requisition
(Lab,Requisition) .. Appointment

Doctor "1" -- "*" Requisition
Requisition "1" - "*" SpecificTest
SpecificTest "1" -- "0..1" TestResult
BusinessHour "7" -- "1" Lab
SpecificTest "*" - "1" Test
Test "*" -- "1" TestType


@enduml

 @startuml

class City {
    String Name
    Int NumberOfInhabitants
}

class Attraction {
    String Name
    String Address
}

class Visitor {}

class GuidedTour {
    Int Number
    Int Duration
}

class Discount {
    Int Discount
}

class Person {
    String Name
}

class Guide {}


City "1"--"*" Attraction
Visitor "1..20"--"*" GuidedTour
Attraction "1"-"*" GuidedTour
Person <|-- Guide
Visitor -|> Person
GuidedTour "*"-"1" Guide
(Visitor,GuidedTour) .. Discount

@enduml

 @startuml

enum Mode { 
    DESIGN
    GAME 
}
enum Color { 
    RED
    BLUE
    GREEN
    YELLOW
}

class TileO {}

class Game {
    int currentConnectionPieces
    Mode mode
    {static} const int SpareConnectionPieces = 32
    {static} const int NumberOfActionCards = 32
}

class Connection {}

class Die {}

class Deck {}

abstract class Tile{
    int x
    int y
    Boolean hasBeenVisited
}

abstract class ActionCard {
    string instructions
}

class RollDieActionCard {}
class ConnectTilesActionCard {}
class RemoveConnectionActionCard {}
class TeleportActionCard {}
class LoseTurnActionCard {}

class WinTile {}
class ActionTile {
   int inactivityPeriod
   int tunrsUntilActive
}
class NormalTile {}

class Player {
    int number
    int turnsUntilActive
    Color color
}

WinTile --|> Tile
Tile <|-- ActionTile
Tile <|-- NormalTile

ActionCard <|-- RollDieActionCard
ActionCard <|-- ConnectTilesActionCard
ActionCard <|-- RemoveConnectionActionCard
ActionCard <|-- TeleportActionCard 
ActionCard <|-- LoseTurnActionCard 

TileO "1" *-- "*" Game : games
Game  "1" *-- "*" Tile : tiles
Game  "1" *-- "*" Connection : connections
Game  "1" *-- "1" Die : die
Game  "1" *- "1" Deck : deck
Game  "1" --> "0..1" Player : currentPlayer
Game  "1" *-- "2..4" Player : players
Deck  "1" *-- "0..32" ActionCard : cards

Game  "1" --> "0..1" WinTile : winTile
Tile  "2" -- "0..4" Connection : connections/tiles
Player "1" --> "0..1" Tile : startingTile
Player "0..4" --> "0..1" Tile : currentTile
Deck  "1" --> "0..1" ActionCard : currentCard
@enduml

 @startuml


abstract class Employee {
  ssNo: int
  name: String
  email: String
  counter: int
}

class Faculty {
  name: String
}

class AdministrativeEmployee

class ResearchAssociate {
  fieldOfStudy: String
}

class Institute {
  name: String
  address: String
}

class Course {
  name: String
  id: int
  hours: float
}

class Lecturer

class Project {
  name: String
  start: Date
  end: Date
}

class Participation {
  hours: int
}

Employee "1" -- "0..1" Faculty : leads >
Employee <|-- AdministrativeEmployee
Employee <|-- ResearchAssociate
Faculty "1" *- "1..*" Institute
Institute "1..*" o-- "1..*" ResearchAssociate
ResearchAssociate <|-- Lecturer
ResearchAssociate "1..*" -- "0..*" Project
Lecturer "1..*" -- "1..*" Course : teaches >
(ResearchAssociate, Project) .. Participation

@enduml
